import {
  BotonTema,
  Footer,
  Header2,
  Github,
} from "../reutilizables/componentes";

import { useEffect, useState } from "react";

function BuscarEliminar() {
  const [usuarios, setUsuarios] = useState([]);
  const [usuarioSeleccionado, setUsuarioSeleccionado] = useState("");

  useEffect(() => {
    const ontenerUsuarios = async () => {
      try {
        const token = localStorage.getItem("token");
        const res = await fetch("http://localhost:4000/api/listarUsuarios", {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });

        const data = await res.json();

        if (!res.ok) {
          alert(data.error || "Error al obtener usuarios");
        }
        setUsuarios(data);
      } catch (error) {
        console.error("Error al obtener usuarios:", error);
      }
    };
    ontenerUsuarios();
  }, []);

  return (
    <div>
      <BotonTema />
      <div id="container">
        <header id="header1">
          <button id="volver" onClick={() => window.history.back()}>
            volver
          </button>
        </header>
        <Header2 />
        <section id="content">
          <p>Seleccione el usuario a eliminar:</p>
          <select id="selectUsuario">
            {usuarios.map((usuario, index) => (
              <option key={usuario.idUsuarios} value={usuario.idUsuarios}>
                {index + 1}. {usuario.idUsuarios} - {usuario.Rol}
              </option>
            ))}
          </select>
          <a href="/confirmacion">
            <button id="buscar" className="principales">
              buscar
            </button>
          </a>
          <button
            id="cancelar"
            className="secundarios"
            onClick={() => window.history.back()}
          >
            cancelar
          </button>
        </section>
        <Footer />
      </div>
      <Github />
    </div>
  );
}

export default BuscarEliminar;
